// // This module decrements the counter value on each positive edge of the clock signal and resets to 7 when the reset signal is active.
module counter_4bit(
    input clk,
    input rst,

    output reg [3:0] count
);
    always @(posedge clk) begin
        if (rst) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end
endmodule
